def least_frequent_word(s):
    words = set(s.lower().split())
    if not words:
        return ''

    freq = {}
    for word in words:
        if word in freq:
            freq[word] += 1
        else:
            freq[word] = 1

    min_count, min_word = float('inf'), None
    for word, count in freq.items():
        if count < min_count:
            min_count, min_word = count, word

    return min_word
